from dataclasses import dataclass
from typing import List

@dataclass
class CacheProcessor:
    cache_name: str
    cache_size: int
    cache_data: List[int]

def initialize_cache(cache_name: str, cache_size: int) -> CacheProcessor:
    cache_data = [0] * cache_size
    return CacheProcessor(cache_name, cache_size, cache_data)

def update_cache(cache: CacheProcessor, index: int, value: int) -> None:
    if 0 <= index < cache.cache_size:
        cache.cache_data[index] = value

def display_cache(cache: CacheProcessor) -> None:
    print(f"Cache Name: {cache.cache_name}")
    print("Cache Data: ", end="")
    for data in cache.cache_data:
        print(data, end=" ")
    print()

def main() -> None:
    cache = initialize_cache("ExampleCache", 10)
    update_cache(cache, 5, 100)
    display_cache(cache)

if __name__ == "__main__":
    main()
